// Generated by GitHub Copilot
import { useEffect, useState } from "react";
import profileFallback from "../data/profileFallback";
import { buildApiUrl } from "../utils/api";

// Generated by GitHub Copilot
/**
 * Build fallback profile data enriched with a live public GitHub snapshot.
 *
 * Security note: this helper only uses public GitHub REST endpoints and does not
 * require client-side secrets.
 *
 * @returns {Promise<Record<string, any>>} Fallback payload with refreshed GitHub profile and repo metadata.
 */
async function buildGithubEnhancedFallbackData() {
  const fallbackUsername =
    profileFallback?.github?.profile?.username ||
    profileFallback?.contact?.github?.split("/").pop() ||
    "Ramdragneel01";

  const [profileResponse, reposResponse] = await Promise.all([
    fetch(`https://api.github.com/users/${fallbackUsername}`),
    fetch(`https://api.github.com/users/${fallbackUsername}/repos?sort=updated&per_page=8&type=owner`),
  ]);

  if (!profileResponse.ok || !reposResponse.ok) {
    throw new Error("GitHub fallback request failed");
  }

  const profilePayload = await profileResponse.json();
  const reposPayload = await reposResponse.json();
  const normalizedRepos = Array.isArray(reposPayload)
    ? reposPayload.map((repo) => ({
        id: String(repo.id),
        title: repo.name,
        description: repo.description || "No description provided yet.",
        readmeSummary: "",
        github: repo.html_url,
        tags: [repo.language, ...(repo.topics || [])].filter(Boolean).slice(0, 4),
        stars: repo.stargazers_count || 0,
        forks: repo.forks_count || 0,
        updatedAt: repo.updated_at || "",
      }))
    : [];

  return {
    ...profileFallback,
    github: {
      profile: {
        username: profilePayload.login || fallbackUsername,
        avatarUrl: profilePayload.avatar_url || "",
        followers: profilePayload.followers || 0,
        following: profilePayload.following || 0,
        publicRepos: profilePayload.public_repos || normalizedRepos.length,
        bio: profilePayload.bio || "",
        profileUrl: profilePayload.html_url || `https://github.com/${fallbackUsername}`,
      },
      repos: normalizedRepos,
    },
    updatedAt: new Date().toISOString(),
  };
}

/**
 * Load portfolio profile payload from backend and provide resilient fallback data.
 *
 * @returns {{data: Record<string, any>, loading: boolean, error: string}} Hook state.
 */
export default function usePortfolioData() {
  const [data, setData] = useState(profileFallback);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState("");

  useEffect(() => {
    let isMounted = true;
    let intervalId;

    /**
     * Load profile payload and optionally preserve current UI state on transient failures.
     *
     * @param {{silent?: boolean}} options Fetch behavior options.
     */
    async function loadProfile(options = {}) {
      const { silent = false } = options;

      try {
        const response = await fetch(buildApiUrl("/profile"));

        if (!response.ok) {
          throw new Error(`Profile request failed with status ${response.status}`);
        }

        const payload = await response.json();
        if (!isMounted) {
          return;
        }

        setData(payload);
        setError("");
      } catch (fetchError) {
        if (!isMounted || fetchError.name === "AbortError") {
          return;
        }

        if (!silent) {
          try {
            const enhancedFallback = await buildGithubEnhancedFallbackData();
            if (!isMounted) {
              return;
            }

            setData(enhancedFallback);
            setError(
              "Live profile API is unavailable. Showing fallback profile data with a live public GitHub snapshot."
            );
          } catch {
            setData(profileFallback);
            setError("Live profile data is unavailable right now. Showing fallback profile data.");
          }
        }
      } finally {
        if (isMounted) {
          setLoading(false);
        }
      }
    }

    loadProfile();

    // Keep profile data near-real-time while respecting resource efficiency.
    intervalId = window.setInterval(() => {
      loadProfile({ silent: true });
    }, 45_000);

    /**
     * Refresh data when the tab becomes active again.
     */
    function handleForegroundRefresh() {
      if (document.visibilityState === "visible") {
        loadProfile({ silent: true });
      }
    }

    document.addEventListener("visibilitychange", handleForegroundRefresh);
    window.addEventListener("focus", handleForegroundRefresh);

    return () => {
      isMounted = false;
      if (intervalId) {
        window.clearInterval(intervalId);
      }
      document.removeEventListener("visibilitychange", handleForegroundRefresh);
      window.removeEventListener("focus", handleForegroundRefresh);
    };
  }, []);

  return { data, loading, error };
}
